#!/usr/bin/env swift

import Foundation

let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath)
let arguments = Array(CommandLine.arguments.dropFirst())

let inputDirectory = arguments.indices.contains(0)
    ? URL(fileURLWithPath: arguments[0], relativeTo: repositoryRoot)
    : repositoryRoot.appending(path: "Sources/swift-figlet/Resources/Fonts", directoryHint: .isDirectory)

let outputFile = arguments.indices.contains(1)
    ? URL(fileURLWithPath: arguments[1], relativeTo: repositoryRoot)
    : repositoryRoot.appending(path: "Sources/swift-figlet-embedded-fonts/swift_figlet_embedded_fonts.swift")

let fileManager = FileManager.default
let supportedExtensions = Set(["flf", "tlf"])

let fontFiles = try fileManager.contentsOfDirectory(
    at: inputDirectory,
    includingPropertiesForKeys: nil
)
    .filter { supportedExtensions.contains($0.pathExtension) }
    .sorted { $0.lastPathComponent < $1.lastPathComponent }

guard !fontFiles.isEmpty else {
    throw NSError(
        domain: "generate_embedded_font_library",
        code: 1,
        userInfo: [NSLocalizedDescriptionKey: "No FIGlet fonts found in \(inputDirectory.path())"]
    )
}

let outputDirectory = outputFile.deletingLastPathComponent()
try fileManager.createDirectory(at: outputDirectory, withIntermediateDirectories: true)

var renderedAssignments: [String] = []
renderedAssignments.reserveCapacity(fontFiles.count)

for fontFile in fontFiles {
    let fontName = swiftStringLiteral(fontFile.deletingPathExtension().lastPathComponent)
    let fontBytes = try Data(contentsOf: fontFile)
    let fontData = String(decoding: fontBytes, as: UTF8.self)
    let chunks = chunked(fontData, maxLength: 4_096)
    var renderedLines = [
        "        fontData = String()",
        "        fontData.reserveCapacity(\(fontBytes.count))",
    ]

    renderedLines.append(contentsOf: chunks.map { chunk in
        "        fontData += \"\(swiftStringLiteral(chunk))\""
    })
    renderedLines.append("        fonts[\"\(fontName)\"] = fontData")

    renderedAssignments.append(
        renderedLines.joined(separator: "\n")
    )
}

let output = """
// Generated by Scripts/generate_embedded_font_library.swift.
// Do not edit by hand.

public import swift_figlet

public enum SwiftFigletEmbeddedFonts {
    public static let library: FigletFontLibrary = {
        var fonts: [String: String] = [:]
        fonts.reserveCapacity(\(fontFiles.count))
        var fontData = String()
\(renderedAssignments.joined(separator: "\n\n"))
        return FigletFontLibrary(
            name: "swift-figlet embedded fonts",
            fontData: fonts
        )
    }()
}
"""

try output.write(to: outputFile, atomically: true, encoding: .utf8)

func chunked(_ value: String, maxLength: Int) -> [String] {
    guard !value.isEmpty else {
        return [""]
    }

    var chunks: [String] = []
    var start = value.startIndex

    while start < value.endIndex {
        let end = value.index(start, offsetBy: maxLength, limitedBy: value.endIndex) ?? value.endIndex
        chunks.append(String(value[start..<end]))
        start = end
    }

    return chunks
}

func swiftStringLiteral(_ value: String) -> String {
    var result = ""
    result.reserveCapacity(value.count)

    for scalar in value.unicodeScalars {
        switch scalar {
        case "\"":
            result += "\\\""
        case "\\":
            result += "\\\\"
        case "\n":
            result += "\\n"
        case "\r":
            result += "\\r"
        case "\t":
            result += "\\t"
        default:
            if scalar.value < 0x20 || scalar.value == 0x7F {
                result += "\\u{\(String(scalar.value, radix: 16))}"
            } else {
                result.unicodeScalars.append(scalar)
            }
        }
    }

    return result
}
